insert into position (id, title, image, first_section, second_section, position_type)
values  (99, 'Pozycja Całkowita rezygnacja', '', 'Kobieta leży na poduszce ułożonej na podłodze lub bardzo twardym materacu. Ma ugięte kolana. Mężczyzna wślizguje się pomiędzy jej uda i penetruje kochankę, pociągając do siebie jej tułów. Podczas poruszania biodrami, mężczyzna może pochylić się i całować lub lizać brzuch partnerki. To on kontroluje ruch, a ona może leżeć i delektować się rozkoszą.', ' ', 'O'),
        (100, 'Pozycja W dolinie przyjemnosci', '', 'Kobieta leży na plecach w rozkroku, a partner penetruje ją, leżąc pomiędzy jej nogami. Kochankowie mają wolne ręce, mogą więc dotykać się i pieścić, a kobieta może głaskać plecy i pośladki partnera. To bardzo prosta pozycja.', ' ', 'O'),
        (101, 'Pozycja Kąt prosty', '', 'Pozycja kąt prosty: Kobieta leży na plecach, układając biodra tuż na krawędzi łóżka lub stołu. Penetrując ją, mężczyzna jednocześnie pieści jej sutki lub łechtaczkę. W innej wersji partnerka nie musi poruszać biodrami - może opleść kochanka nogami. On napierając na nią ciężarem, dostarczy obojgu bardzo intensywnej przyjemności. To bardzo stymulująca pozycja, ponieważ mężczyzna czuje każdy skurcz pochwy partnerki, a ona czuje każdy ruch penisa.', ' <h2 class="heading"> Pozycja kąt prosty- dla kogo się nadaje? </h2> <p class="paragraph">Na pewno dla tych osób, które są gibki! Kąt prosty to też jednak pozycja, która przyniesie - zwłaszcza kobietom - ogromną satysfakcję!</p> ', 'O'),
        (102, 'Pozycja Akt równowagi', '', 'Mężczyzna leży na plecach, nogi zgięte. Trzyma kobietę siedzącą przed nim mocno w talii. W tej pozycji mężczyzna kontroluje rytm ruchów. Ona trzyma nogi wysoko uniesione i przyciśnięte do klatki piersiowej.', ' ', 'O'),
        (103, 'Pozycja Siła grawitacji', '', 'Pozycja Siła grawitacji: Mężczyzna stoi, partnerka obejmuje go nogami w talii, podczas gdy on podtrzymuje jej pośladki, by nie straciła równowagi. Aby zapewnić sobie lepsze oparcie i głębszą penetrację, kobieta może oprzeć się plecami o ścianę. Ta pozycja może być wykonana wszędzie, o każdej porze dnia i nocy... Tylko partner musi być bardzo silny, by utrzymać partnerkę.', ' <h2 class="heading"> Pozycja Siła grawitacji. Czy nadaje się dla każdego? </h2> <p class="paragraph">Raczej nie. Pozycja siła grawitacji przeznaczona jest przede wszystkim dla tych, którzy mają już doświadczenie w różnego rodzaju pozycjach.</p> ', 'O'),
        (104, 'Pozycja Leniwa dziewczyna', '', 'Pozycja Leniwa dziewczyna: Mężczyzna klęka i odchyla się do tyłu, opierając się na rękach. Partnerka kładzie się na plecach z głową na poduszce. Ugina kolana, tak aby umieścić pochwę na wysokości odpowiedniej do penetracji. Kobieta ma wolne ręce, może więc pieścić się podczas stosunku. Ta mocno erotyczna pozycja umożliwia głęboką penetrację, kontrolę ze strony mężczyzny i obserwowanie reakcji partnerki.', ' <h2 class="heading"> Pozycja Leniwa dziewczyna. Jak to wygląda w praktyce? </h2> <p class="paragraph">Wiele z nas może się zastanawiać, czy faktycznie, kobieta jest "leniwa". Ależ skąd - to tylko pozory. Dajcie się "wkręcić" w pozycję leniwa dziewczyna, a na pewno nie pożałujecie. Dotyczy to zarówno kobiet, jak i mężczyzn.</p> ', 'O'),
        (105, 'Pozycja Hot dog', '', 'Pozycja Hot dog: Mężczyzna leży na plecach, partnerka siada na nim okrakiem. Wspiera się na łokciach, ma ugięte kolana, a stopy stawia na kolanach partnera. Kochanek penetruje kochankę od tyłu, może kontrolować jej ruchy, trzymając ją w talii. Partnerka unosi i opuszcza biodra, pozwalając w ten sposób na głębszą penetrację. Tę pozycję można wykonać także, gdy partnerka zwrócona jest twarzą do partnera.', ' <h2 class="heading"> Pozycja Hot dog. Dlaczego jest tak popularna? </h2> <p class="paragraph">Pozycja hot dog, wbrew pozorom, jest niezwykle popularna. Wszystko dlatego, że jest w stanie przynieść niesamowite doznania zarówno kobiecie, jak i mężczyźnie.</p> ', 'O'),
        (106, 'Pozycja Szerokie otwarcie', '', 'Pozycja szerokie otwarcie: Mężczyzna klęczy przed partnerką, która płasko leży na plecach. Ona unosi pośladki i uda, oplatając go nogami w pasie. Kochanka może wygiąć ciało w łuk tak, by partner mógł podtrzymywać jej plecy.', ' <h2 class="heading"> Pozycja szerokie otwarcie. Czy warto? </h2> <p class="paragraph">Jak najbardziej! Pozycja szerokie otwarcie będzie w stanie wam zapewnić maksymalną przyjemność z seksu.</p> ', 'O'),
        (107, 'Pozycja Łuk triumfalny', '', 'Pozycja Łuk triumfalny: Mężczyzna siedzi z nogami wyciągniętymi na łóżku. Kobieta siada na jego kolanach, podkula nogi. Po znalezieniu wygodnej pozycji, wygina się w tył i kładzie na jego nogach. Jej głowa jest mniej więcej między nogami mężczyzny. Mężczyzna pochyla się. Poza penetracją może pieścić całe ciało partnerki.', ' <h2 class="heading"> Pozycja Łuk triumfalny. Czy naprawdę jest przyjemna? </h2> <p class="paragraph">Jak najbardziej! Będzie od was wymagała poświęcenia, ale możecie być przekonani, że pozycja łuk triumfalny jest tego warta.</p> ', 'O'),
        (108, 'Pozycja Ślimak', '', 'Leżąc, kobieta przyciąga kolana do klatki piersiowej i opiera stopy o ramiona partnera. On penetruje ją, klęcząc przed nią i podpierając się na rękach. Ponieważ jest to pozycja umożliwiająca bardzo głęboką penetrację, powinna być wypróbowywana tylko, gdy pochwa jest dobrze nawilżona, by uniknąć bólu. Ta pozycja mocno stymuluje kobietę, szczególnie jeśli u mężczyzny dochodzi do wytrysku.', ' ', 'O'),
        (109, 'Pozycja seksualna: boczne pchnięcie', '', '<p><span><b>Boczne pchnięcie</b> to pozycja polecana głównie wtedy, gdy trzeba uważać na <b>stawy biodrowe kobiety</b>. Jeśli to partner ma kłopoty z biodrem, powinien leżeć na plecach i nie nadwyrężać bioder ani kręgosłupa dynamicznymi ruchami frykcyjnymi.</span></p><p><span><b>O co chodzi?</b><br></span></p><p><span>Kobieta leży na brzuchu. Partner klęka obok niej, odwodzi ostrożnie jej nogę do boku (nie do góry) i klęka między nogami - jedna noga na zewnątrz, jedna między jej udami. Mężczyzna kontroluje intensywność pchnięć, wysuwając zewnętrzną nogę do przodu. </span></p><p><span><b>Pozycja</b> pozwala pieścić plecy kochanki, więc sprawdza się również przy bólach kręgosłupa.</span></p><p><b>Warto wiedzieć</b></p><p><span>W przypadku problemów z biodrami, zasadniczo bezpieczne <b>pozycje seksualne</b> to wszystkie te, które pozwalają uniknąć krzyżowania nóg i wyginania stawów biodrowych o więcej niż 90 stopni. </span></p><p><span>Po wymianie stawu biodrowego przez pierwsze trzy miesiące od zabiegu, po uzyskaniu zgody od lekarza na powrót do aktywności seksualnej, wskazane wyłącznie pozycje na plecach. Potem zalecane są także boczne, ale bez owijania nóg wokół partnera (jak <b>łyżeczki</b> czy <b>na ławeczce</b> - patrz następna strona).</span></p>', '', 'ZG'),
        (110, 'Pozycja seksualna: most jęków', '', '<p><span><span class="Object"><span class="Object"><b>M</b><b>ost jęków</b> to pozycja przyjazna <b>dla kręgosłupa</b> kobiety i mężczyzny. Łatwa, przyjemna, a w bonusie zapewnia wzmocnienie mięśni lędźwiowych i pośladków. Działa profilaktycznie i leczniczo. W przypadku aktywnego, poważnego schorzenia niewskazana, ale wówczas lekarz wyraźnie zakazuje aktywności fizycznej, a chory, przynajmniej czasowo, nie ma na nią ochoty.</span></span></span></p><p><span><span class="Object"><span class="Object"><b>O co chodzi?</b><br></span></span></span></p><p><span><span class="Object"><span class="Object">Kobieta kładzie się na plecach, zgina nogi w kolanach, a ciężar ciała przenosi na stopy. Nogi rozsuwa szeroko, a biodra unosi. Może również podłożyć pod pośladki i kręgosłup ortopedyczną poduszkę. To odciąży jej kręgosłup. Pozycja gwarantuje, że <b>penis</b> partnera stymuluje najbardziej unerwione części pochwy. </span></span></span></p><p><span><span class="Object"><span class="Object">Jeśli kobieta zaciska uda na biodrach mężczyzny, wzmacnia doznania obojga kochanków.</span></span></span></p><p><b>Warto wiedzieć</b></p><p><span><span class="Object"><span class="Object">Powszechnie uważa się, że w przypadku nawracających dolegliwości ze strony kręgosłupa optymalna jest klasyczna pozycja misjonarska.</span><span class="Object"> </span></span><span class="Object"><span class="Object"> Tymczasem: nie jest zalecana ze względu na ryzyko mikrourazów. Podobnie niekorzystne są wszelkie inne <b>pozycje</b>, które wymagają wyginania do tyłu. To zagrożenie (przy w pełni pasywnej kobiecie) istnieje szczególnie dla kręgosłupa mężczyzny, więc jeśli to on ma problem, zapomnijcie o klasyce. </span></span></span></p><p><span> </span></p><p><span><span class="Object"><span class="Object"><b>Misjonarska</b> tak, ale po modyfikacji umożliwiającej odciążenie części lędźwiowej kręgosłupa. Pozwala na to ugięcie kolan i bioder pod jakimkolwiek kątem . Następuje wówczas rozluźnienie mięśni lędźwiowo-udowych. Pozycja ta jest jednak przyjazna głównie kobiecie, jeśli odczuwa ona bóle kręgosłupa.</span></span></span></p>', '', 'ZG'),
        (111, 'Pozycja seksualna: zmodyfikowana kowbojka tyłem', '', '<p><span><b>Zmodyfikowana kowbojka tyłem</b> to pozycja idealna dla mężczyzn z urazami kręgosłupa.</span></p><p><span><b>O co chodzi?</b><br></span></p><p><span>Mężczyzna od głowy do palców stóp musi mieć solidne podparcie, najlepiej wzmocnione (np. poduszką) górnego odcinka kręgosłupa. Sprawdzi się zatem małżeńskie łoże, ale także podłoga.</span></p><p><span>Kobieta, by zapewnić rozluźnienie mięśni dolnego odcinka kręgosłupa, powinna zgiąć nogi w kolanach i siedzieć szeroko, a zarazem stabilnie. </span></p><p><span><b>Pozycja</b> ułatwia pieszczenie łechtaczki i pozwala kobiecie kontrolować tempo zbliżenia.</span></p><p><span><b>Warto wiedzieć</b></span></p><p><span>Zmodyfikowana <b>pozycja na jeźdźca</b> nie tylko tyłem może być odpowiednia dla par, które mają problemy z kręgosłupem. Istotne jest odpowiednie oparcie dla partnera. <br></span></p><p><span> Zapomnijcie o tej <b>pozycji</b> na skraju łóżka, gdy trzeba szukać równowagi i stabilizacji.</span></p>', '', 'ZG'),
        (112, 'Pozycja seksualna: na ławeczce', '', '<p><span><b>Na ławeczce</b> to kolejna <b>pozycja seksualna</b> przyjazna stawom biodrowym i kręgosłupowi. </span></p><p><span><b>O co chodzi?</b></span></p><p><span>Kobieta przekłada złączone nogi ponad biodrami mężczyzny, a on przylega do niej całym ciałem. Dzięki zaciśnięciu kobiecych ud mocniej pieszczone są boczne ścianki pochwy. Stymulacja penisa również jest silniejsza.</span></p><p><span><b>Zalety pozycji</b><br></span></p><p><span>Nie wymaga sporego wysiłku. Nie przeciąża konkretnych partii ciała, a zarazem umożliwia na szczególną bliskość i więź między partnerami.</span></p><p><span>Możecie patrzeć sobie w oczy. Okazywać czułość. Można się tulić, całować, obejmować, a zarazem nikt nie jest nadmiernie uciskany.</span></p>', '', 'ZG'),
        (113, 'Pozycja seksualna na siedząco tyłem', '', '<p><span><span class="Object"><span class="Object">Pozycja przyjazna dla tych, których często plecy bolą. <span>Klasyczne pozycje seksualne siedzące <span><span class="Object"><span class="Object"><span> </span></span></span></span>zwykle nie są przyjazne kręgosłupowi (ze względu na trudności z przenoszeniem ciężaru ciała na kończyny, obciążenie partnera),</span> ale ta jest wyjątkowa.<br></span></span></span></p><p><span><b>O co chodzi?</b><br></span></p><p><span>Potrzebna jest duża, wygodna wanna, gwarantująca oparcie dla pleców mężczyzny. Woda ujmuje ciału ciężaru, kąpiel działa rozgrzewająco i odprężająco.</span></p><p><span>Nie trzeba mieć silnych nóg, można je swobodnie, wygodnie ułożyć. Istotne jednak, żeby wanna była naprawdę spora. Jeśli zadbacie jeszcze o odpowiednie olejki, świece zapachowe, a mężczyzna zrobi użytek z wolnych rąk, to może być ekscytujące doświadczenie.</span></p>', '', 'ZG'),
        (114, 'Pozycja seksualna: zmodyfikowane taczki', '', '<p><span><span class="Object"><span><span class="Object"><span class="Object">Pozycja polecana osobom z <b>chorobami serca</b> i innymi problemami krążeniowymi. Także, gdy jesteście zmęczeni, raczej leniwi a także, gdy plecy bolą (on twoje może głaskać, jego są bezpiecznie odsunięte). </span></span></span></span></span></p><p><span><span class="Object"><span><span class="Object"><span class="Object">Uwaga! Ucisk na biodro kobiety może powodować jej dyskomfort i nie jest wskazany, gdy są z nim problemy.</span></span></span></span></span></p><p><span><span class="Object"><span><span class="Object"><span class="Object"> </span></span></span><b>O co chodzi?</b></span></span></p><p><span><span class="Object"><span class="Object">Partner wsuwa się między nogi partnerki i nie tylko penetruje pochwę, ale także stymuluje strefy erogenne, w tym łechtaczkę. Może także pieścić <b>piersi</b>. Kobieta jest mniej aktywna, ale skoro chodzi głównie o relaks...</span></span></span></p><p><span><span class="Object"><span class="Object">Oboje leżycie na boku. Jeśli mężczyzna podłoży poduszkę pod górną część pleców i głowę, ucisk na biodro może być mniejszy.</span></span></span></p><p><b><span><span class="Object">Warto wiedzieć</span></span></b></p><p><span><span class="Object"><span class="Object">Klasyczna <b>pozycja seksualna taczki</b> wymaga sporej sprawności fizycznej i uchodzi za nienaturalną, dlatego nie lubią jej kobiety. To raczej rodzaj gimnastyki seksualnej, zwłaszcza jeśli sprawność fizyczna jest już uniedogodnieniem.</span></span></span></p><p><span><span class="Object"><span class="Object">Tymczasem w <b>pozycji leżącej</b>, na dużym łóżku, ułożeni jak do taczki, możecie sprawiać sobie przyjemność bez większego wysiłku.</span></span></span></p><p><span><span class="Object"><span class="Object">Warto pamiętać, że osoby z chorobami układu krążenia zwykle boją się nadmiernego wysiłku. <b>Serce</b> to mięsień, który wymaga racjonalnego obciążania, ale osoby chore potrzebują trochę czasu, by to zrozumieć i oswoić się z lękiem. Seks jest dla organizmu znacznym wysiłkiem, zatem jeśli przyjmujesz leki nasercowe, zapytaj swojego lekarza prowadzącego, czy aktywność fizyczna jest dla ciebie wskazana, lub ile czasu po zabiegach/operacjach powinieneś poczekać na podjęcie współżycia. </span></span></span></p><p><span><span class="Object"><span class="Object">Do tego czasu możecie się całować, pieścić, dotykać, co zwiększa poczucie bliskości i buduje intymność.</span></span></span></p>', '', 'ZG'),
        (115, 'Pozycja seksualna: na pieska', '', '<p>Zacznijmy od klasyki, czyli pozycji <b>na pieska.</b></p><p><span><b>Jak to wygląda?<br></b></span></p><p><span>Partner klęka za kochanką. Ta pochyla się do przodu, zazwyczaj klęcząc i opierając się na łokciach lub dłoniach. Partnerka może też położyć tułów na łóżku lub krześle, pozostać na wyprostowanych rękach. Im wyżej znajdują się pośladki, tym penetracja jest głębsza.</span></p><p><span><b>Zalety:</b><br></span></p><p><span><b>Pozycja seksualna na pieska</b> umożliwia stymulację bardzo wrażliwych partii kobiecego ciała. <span>Wolne ręce mężczyzny pozwalają mu przede wszystkim pieścić kobiece piersi, to on także ma pełną kontrolę nad sytuacją i tempem. </span></span></p><p><span><span>Jednocześnie widok i tak bliski kontakt z pośladkami partnerki może dodatkowo wzmacniać podniecenie.</span></span></p><p><b>Warto wiedzieć:</b></p><p><span><span><span>Pozycja bywa też nazywana <b>tylną</b> lub <b>kolanowo-łokciową</b>. </span></span></span></p><p><span>Część kobiet ma opory przed <b> pozycjami od tyłu</b> i nie ma sensu się do nich zmuszać na samym początku znajomości. Gdy się jednak lepiej poznacie i przekonacie, że bliskość i czułość jest możliwa nie tylko twarzą w twarz, warto spróbować. Dobrze zacząć od czegoś prostego, jak właśnie ta pozycja.</span></p>', '', 'ZG'),
        (116, 'Pozycja seksualna: żabka', '', '<p><span>Nietrudno zauważyć, że na rysunku ta pozycja jest łudząco podobna do <b>pozycji na pieska</b>. To jednak nie do końca to samo. Przede wszystkim <b>żabka</b> jest wygodniejsza, dlatego jest lubiana nawet przez kobiety w zaawansowanej ciąży.<br></span></p><p><span><b>Jak to wygląda?</b><br></span></p><p><span>Kobieta odwraca się plecami do partnera, klęka, pochyla ciało do przodu i kładzie głowę na poduszce. Równocześnie: lekko wypina pośladki w kierunku partnera. Czyli: tułów niżej, <span>pupa wyżej. K</span>ark się nie męczy, dostęp do <b>waginy</b> jest łatwiejszy, a penetracja głębsza. </span></p><p><span>Zazwyczaj kobietom jest wygodnie tak rozsunąć mocno ugięte nogi, że rzeczywiście przypominają nieco <b>żabkę</b> szykującą się do skoku. To głównie klęczący z tyłu mężczyzna kontroluje jednak intensywność i tempo penetracji. </span></p><p><b><span>Zalety:</span></b></p><p><span><b>Żabka</b> to <b>pozycja</b> <b>seksualna</b>, która pozwala swobodnie się kochać partnerom o sporej różnicy wagi (on grubszy, ona szczupła, ona w ciąży, itd.), a także wzrostu.</span></p><p><span><span>Mężczyzna ma możliwość obdarzać <span><span>kochankę </span></span>pieszczotami: od pleców począwszy, na <b>łechtaczce</b> skończywszy.</span></span></p><p><span>Wśród <b>pozycji tylnych żabka</b> należy do popularniejszych. Prawdopodobnie dlatego, że nie wymaga dobrej kondycji ani fizycznej sprawności. </span></p><p><span> </span></p>', '', 'ZG'),
        (117, 'Pozycja seksualna: tylna z oparciem', '', '<p>Nie dla wszystkich kobiet klęczenie jest komfortowe, wtedy lepiej zacząć od <b>pozycji tylnej z oparciem</b>.</p><p><span><b>Jak to wygląda?<br></b></span></p><p><span>Kobieta opiera się wygodnie o mebel (łóżko, krzesło, stolik) i wypina pośladki w kierunku partnera tak, by wagina (lub odbyt) znalazły się na wysokości <b>penisa</b>. <span>Zasadniczo kobieta w tej pozycji pozostaje bierna, ale to nie oznacza, że nie ma żadnego wpływu na przebieg miłosnego aktu. <br></span></span></p><p><span><b>Zalety:</b></span></p><p><span>Ta pozycja, podobnie jak wiele innych od tyłu, pozwala na silną stymulację przedniej ściany pochwy wraz z <b>punktem G</b>. Kobieta poprzez umiejętne ułożenie bioder i okrężne ruchy miednicą może dodatkowo zintensyfikować swoje doznania. </span></p><p><span>Także kochanek ma szansę na niezapomniane, nieraz nowe przeżycia. Wystarczy, że kobieta zewrze nogi - pochwa zwęzi się wówczas, przez co tarcie stanie się silniejsze.<br></span></p><p><b><span>Warto wiedzieć:</span></b></p><p><span>Wśród<b> pozycji od tyłu</b> dla kobiet szczególnie przyjazne są właśnie te, które zapewniają oparcie (np. o ścianę, solidny stolik, kanapę o właściwej wysokości, etc.). Panie czują się pewniej i mniej się męczą. Uwaga na kanty - w miłosnym uniesieniu <span>łatwo o skaleczenie</span> czy inne uszkodzenia.</span></p>', '', 'ZG'),
        (118, 'Pozycja seksualna: na łyżeczkę (łyżeczka, łyżeczki)', '', '<p>To jedna z najbardziej znanych pozycji. Zwykle podoba się początkującym kochankom, ale także parom z dużym stażem. O tej pozycji naprawdę nie da się powiedzieć, że nie zapewnia takiej bliskości i czułości, jak te twarzą w twarz.</p><p><b><span>Jak to wygląda?<br></span></b></p><p><span> </span><span><span></span></span><span></span><span><span>Kobieta leży na boku, a leżący za nią partner wprowadza członka do pochwy. Możliwa też wersja analna, jak w większości pozycji od tyłu. <b>Więcej o seksie analnym. </b><span><span>Mimo że zakres ruchów jest tu niewielki, to wolne ręce obojga partnerów mogą wzmacniać doznania (można dostać się do <b>łechtaczki</b>, pieścić piersi).</span></span></span></span><span></span></p><p><b><span><span>Zalety:</span></span></b></p><p><span> </span><span><span></span></span><span></span><span><span><span><span><span>Pozycja pozwala na szczególną bliskość. Dodatkową jej zaletą jest intensywna stymulacja <b>punktu G</b>. </span></span></span></span></span></p><p><span><span><span><span><span>P<span>ozycja może spełniać rolę spokojnej i leniwej, niewymagającej wysiłku stymulacji, ale również mężczyzna może przytrzymywać pośladki kobiety i regulować tempo pchnięć, co dodatkowo urozmaici stosunek.</span></span></span></span></span></span></p><p><span> </span><span></span><span><span><b>Na łyżeczkę</b> fajnie jest też zasnąć.</span></span></p><p><span><span><span><span>Specyficzne ułożenie sprawia, że stosunek jest dłuższy. Pozycja idealna dla leniuchów: nie wymaga dużego wysiłku od żadnej ze stron.</span></span></span></span></p>', '', 'ZG'),
        (119, 'Pozycja seksualna: Lady Makbet', '', '<p><span>Może znowu wykorzystajmy jakiś mebel? <b>Lady Makbet</b> to pozycja, która pozwala rządzić nawet drobnym paniom, na co dzień zdominowanym przez kochanka.<br></span></p><p><span><b>Jak to wygląda?<br></b></span></p><p><span>To pozycja <span>tylna </span>siedząca. Ona siada na nim tyłem. Jej nogi znajdują się po obu stronach ud mężczyzny. Kochanka ma sporą swobodę ruchów, decyduje o tempie i głębokości penetracji. <br></span></p><p><b><span>Zalety:</span></b></p><p><span><b>Lady Makbet</b> pomaga przełamać się kobiecie, która ma opory przed pozycjami tylnymi. Partnerka ma tu dużo do powiedzenia. </span></p><p><span><span>Pozycja pozwala przy tym na szczególną bliskość, czułość. On może ją przyciskać do siebie, ale także pieścić <b>piersi</b>. </span></span></p><p><span><span>Jeśli jego brzuch nie jest ogromny, nie ma problemu, by dłońmi dostał się także do <b> łechtaczki</b>.</span></span></p>', '', 'ZG'),
        (120, 'Pozycja seksualna: na siedząco, tyłem', '', '<p><span><span class="Object"><span class="Object">Właściwie można tę pozycję wypróbować wszędzie. Jeśli jednak próbujesz otworzyć partnerkę na pozycje od tyłu, macie odpowiednie warunki i zależy wam na odprężającym relaksie, warto zacząć od tej na siedząco.<br></span></span></span></p><p><span><b>Jak to wygląda?</b></span></p><p><span>Mężczyzna siada pierwszy, jeśli to możliwe: opierając wygodnie plecy. Kobieta siada między jego nogami. Po dopasowaniu możecie się dotykać, myć, przytulać. Potrzebna jest duża, wygodna wanna, gwarantująca oparcie dla pleców mężczyzny. </span></p><p><span>Woda ujmuje ciału ciężaru, kąpiel działa rozgrzewająco i odprężająco. </span></p><p><span>Nie trzeba mieć silnych nóg, można je swobodnie, wygodnie ułożyć. </span></p><p><span>Jeśli zadbacie jeszcze o odpowiednie olejki, świece zapachowe, a mężczyzna zrobi użytek z wolnych rąk, to może być ekscytujące doświadczenie.</span></p><p><span><span><span class="Object"><span class="Object">Pozycja przyjazna dla tych, których często plecy bolą. <span>Klasyczne pozycje seksualne siedzące <span><span class="Object"><span class="Object"><span> </span></span></span></span>zwykle nie są wygodne dla kręgosłupa (ze względu na trudności z przenoszeniem ciężaru ciała na kończyny, obciążenie partnera),</span> ale ta jest wyjątkowa. To głównie wsparcie dla pleców kochanka i zalety wody zmieniają wszystko.</span></span></span></span></p>', '', 'ZG'),
        (121, 'Pozycja seksualna: jeździec tyłem (inaczej)', '', '<p><span><span><span><span>Kolejny ciekawy wariant <b>pozycji na jeźdźca</b>. Dlaczego uważamy, że jest nieco trudniejszy od wcześniejszej kowbojki? Przyjrzyjcie się nogom kobiety: będzie jej mniej wygodnie i szybciej się zmęczy. Z drugiej strony: widoki dla niego szczególnie ponętne.<br></span></span></span></span></p><p><span><b>Jak to wygląda?</b><br></span></p><p><span><span><span><span>Niemal wszystko jest na opak. <span>Ona siedzi tyłem (on może podziwiać jej pośladki, <span>dotykać piersi, a jeśli kobieta uniesie tułów, głaskać po plecach</span>), a dodatkowo pochyla się do przodu i <span>jeśli potrzebuje, może dotykać swojej <b>łechtaczki</b></span></span></span></span><span>.</span><br></span></span></p><p><b><span><span>Zalety:</span></span></b></p><p><span><span>Pozycja zapewnia silną stymulację i optymalną penetrację, a zarazem nie męczy się szyja i plecy kobiety. </span></span></p><p><span><span>Oparcie na rękach jest wygodne, a w dodatku kontrola rytmu oraz odpowiednie ustawianie kąta pieszczot jest niezwykle proste. </span></span></p><p><span><span>Łatwo tu o ważną w seksie precyzję (pozwala na to łagodny balans ciałem).</span></span></p>', '', 'ZG'),
        (122, 'Pozycja seksualna: przekładaniec na boku', '', '<p><span><b>Przekładaniec</b> to takie łyżeczki, ale trochę bardziej skomplikowane. Spodoba się wam, jeśli lubicie się kochać długo i powoli.<br></span></p><p><span>Kobieta kładzie się na brzuchu obok partnera. On leży na boku. Partnerka przekłada nogi przez jego biodra tak, by jego <b>penis</b> mógł dosięgnąć pochwy. Pozycja wymaga odrobiny gimnastyki. Partner musi wytrzymać napór jej ciała i utrzymać na boku. Czasem jest wygodniej, gdy kochanka położy się także częściowo na boku, jak na rysunku.<br></span></p><p><span>Jeśli lubicie pozycję na <b>łyżeczkę</b>, a zarazem potrzebujecie odświeżenia i zmiany, oto ona. <br></span></p><p><span>Chociaż nie kochacie się cały czas twarzą w twarz, w tej pozycji jesteście naprawdę blisko.</span></p><p><span>Pozycja umożliwia stymulację <b>łechtaczki</b> i dość prostą regulację głębokości penetracji.</span></p>', '', 'ZG'),
        (123, 'Pozycja seksualna: uścisk ogiera (od tyłu, na leżąco)', '', '<p><span>To lekko zmodyfikowana pozycja klasyczna od tyłu. Ponieważ jednak diabeł tkwi w szczegółach, właśnie niewielka zmiana może zapewnić unikalną rozkosz i fantastyczny orgazm.</span></p><p><span> </span><span>Ona kładzie się na brzuchu i tak pozostaje. Powinna unosić pośladki powoli tak, by umożliwić partnerowi penetrację, a potem wsuwanie penisa w kochankę na różną głębokość.</span></p><p><span> </span><span>Teoretycznie łatwo z tej pozycji przejść do tradycyjnej pozycji na pieska, jednak zostając w leżącej przy szybkich ruchach frykcyjnych kobieta będzie lekko przesuwać się po powierzchni łóżka czy miękkiego dywanu. To może zapewnić dodatkową stymulację łechtaczki.</span></p><p><span><b>Warto wiedzieć:</b></span></p><p><span> </span><span>Pozycja bywa nazywana <b>uściskiem ogiera</b>, ale częściej spotyka się jednak zwyczajną nazwę od tyłu, na leżąco. <b>Uściskiem ogiera</b> nieraz nazywa się pozycję, w której kobieta leżąca i penetrowana od tyłu, stopami (lub nawet nogami poniżej kolan, gdy jest dość wygimnastykowana) obejmuje pośladki kochanka.</span></p>', '', 'ZG'),
        (124, 'Pozycja seksualna: sfinks', '', '<p>W <b>uścisku ogiera</b> ona jest zupełnie pasywna. A gdyby tak zrobić użytek z nóg lub chociaż jednej? Czas na <b>sfinksa</b>.</p><p><span>Nazwę pozycja zawdzięcza kształtowi ciała kobiety przyjmowanemu w tej pozycji. Partnerka kładzie się na brzuchu i opiera na przedramionach, a następnie zgina w kolanach jedną nogę. Nogi rozsuwa tak, by zmieścił się między nimi mężczyzna. Ten nachyla się nad kobietą i penetruje ją od tyłu, podpierając się na rękach. W zależności od upodobań może to być stosunek waginalny lub <b>analny</b>. </span></p><p><span>W tej pozycji seksualnej zazwyczaj oboje partnerzy osiągają intensywny <b>orgazm</b>.</span></p><p><span>Jeśli tylko kobieta lubi pozycje od tyłu, ta pozycja jest raczej lubiana.</span></p><p><span>Pozycja pozwala na czułość, bliskość, głaskanie i pocałunki.</span></p><p><span>Mogą ścierpnąć wam nogi, ale wtedy można pomyśleć o zmianie strony.</span></p>', '', 'ZG'),
        (125, 'Pozycja seksualna: siad w rękach', '', '<p>Ta <b>pozycja</b> to już nie przelewki. Chociaż stopień trudności ma stosunkowo niski, dotyczy to jedynie sytuacji, gdy kobieta ma naprawdę silne nogi.</p><p><span><b>Jak to wygląda?</b></span></p><p><span>Kobieta stoi na podwyższeniu i zgina nogi w kolanach. Tuż za nią ustawia się mężczyzna tak, by zapewnić jej dodatkową asekurację. Pełną kontrolę nad szybkością i głębokością penetracji ma mężczyzna. </span></p><p><span><span>Aby wykonać tę pozycję prawidłowo, potrzebne jest łóżko lub krzesło - po zgięciu przez kobietę kolan jego i jej genitalia muszą się znaleźć na podobnej wysokości.</span></span></p><p><b>Zalety:</b></p><p>To dość ekscytujący sprawdzian zaufania kochanków: ona musi wierzyć, że on ją utrzyma, partner zawierza własnym umiejętnościom.</p><p>Znowu <b>pozycja od tyłu</b>, a zarazem tyle okazji do czułości i pieszczot.<b><br></b></p><p><span> </span><span></span><span><b>Warto wiedzieć: </b></span></p><p><span>Oczywiście, test przyjemny, chociaż pozorny. Niby to siad w rękach (jego), ale to odpowiedni mebel sprawia głównie, że ona jest bezpieczna i daje radę. Chyba, że cały czas wybiera opcję: na palcach. Wtedy o równowagę ciężko.</span></p><p><span> </span><span></span><span>Jeśli partnerka ma słabe mięśnie nóg, pozycja może być dla niej bardzo nieprzyjemna, a parze trudno będzie wytrwać. Można sobie pomóc opierając dłonie o ścianę lub półkę - wtedy łatwiej rozłożyć ciężar ciała oraz koordynować i kontrolować ruchy partnera w czasie penetracji.</span></p>', '', 'ZG'),
        (126, 'Pozycja seksualna: nożyce tyłem', '', '<p>Te <b>nożyce</b> wydają się trudne? Jeśli dotrzecie <b>do strony 25</b>, przekonacie się, że mogą być naprawdę skomplikowane.</p><p><span><b>Jak to wygląda?</b><br></span> <span><br> To kolejna modyfikacja <b>pozycji na jeźdźca tyłem</b>. Mężczyzna kładzie się na plecach, a nogi przyciąga do klatki piersiowej. Partnerka dosiada go tyłem. Plecami opiera się o jego stopy. Swoje palce stóp opiera o podłoże. Kochankowie mogą trzymać się za ręce, by ułatwić sobie utrzymanie się w tej pozycji.</span></p><p><span>Unikalne widoki i ciekawa odmiana, jeśli jeszcze tego nie próbowaliście.<br></span></p><p><span><span>Chociaż penetracja nie jest zbyt głęboka, <b>penis</b> skutecznie dotyka przedniej ściany pochwy, stymulując <b>punkt G</b>.</span></span></p><p><span><span><span>Kobiety lubią tę pozycję, podobnie jak inne wersje <b>kowbojki tyłem</b>.</span></span></span></p><p><b><span>Warto wiedzieć:</span></b></p><p><span> </span><span>Tu rządzi ona, ale też kobieta najwięcej pracuje. To raczej znośna cena za przyjemność.</span></p><p><span> </span><span><b>Pozycja</b> bywa męcząca. Dla większej wygody, zamiast opierać się na palcach, ona może stawiać całe stopy na podłożu.</span></p><p><span> </span>Pozycja okazuje się też trudna dla mężczyzny. Jemu <span>może dokuczyć <b>kręgosłup</b> i nogi.</span></p><p><span> </span></p>', '', 'ZG'),
        (127, 'Pozycja seksualna: na napastnika', '', '<p>Wydaje ci się, że to łatwa pozycja, która nie różni się właściwie od wcześniejszego <b>jeźdźca tyłem</b>? Poznaj szczegóły, zmienisz zdanie.</p><p><span><b>Jak to wygląda?</b></span></p><p><span>On leży na plecach, obie nogi ma ugięte. Ona odwraca się do niego plecami i siada na niego okrakiem. Opiera się rękami o jego kolana. On pieści jej pośladki i piersi.</span></p><p><span>W tej pozycji <b>orgazm</b> bywa wyjątkowy.</span></p><p><span>Mężczyźni uwielbiają tę pozycję, bo gwarantuje im także wzrokowe doznania. </span></p><p><span><span>Kobiety cenią sobie fakt, że to one ustalają tempo.</span></span></p><p><span><b>Warto wiedzieć:</b></span></p><p><span>Niektóre pary, które próbowały tej pozycji i choćby <b>nożyc tyłem</b>, wyglądających przecież na bardziej skomplikowane, przyznają, że to właśnie <b>pozycja na napastnika</b> jest wyzwaniem. </span></p><p><span><b>Penis łatwo może się wysunąć z pochwy</b> (już samo celowanie nie jest łatwe), więc rzeczywiście musi być spory. Panowie o rozmiarze standardowym po takim seksie nieraz wpadają w kompleksy.</span></p><p><span> Kobiety narzekają, że "nogi jakoś się nie mieszczą" do tego klęczenia, a także bolą (podobnie jak plecy). Czasem kochankowie miewają wrażenie, że jakoś do siebie "nie pasują".</span></p>', '', 'ZG'),
        (128, 'Pozycja seksualna: prowokacja', '', '<p>Ta pozycja to nie tylko propozycja. To <b>prowokacja.</b></p><p><b><span>Jak to wygląda?<br></span></b></p><p><span>Kobieta kuca na krześle lub łóżku. Partner chwyta ją za biodra i zaczyna penetrację. Od niego zależy intensywność ruchów i ich rytm.</span></p><p><b><span>Zalety:</span></b></p><p><span>Jeśli on marzył o kochance uległej, ale zarazem bardzo chętnej, ta pozycja pozwala wierzyć, że właśnie ją znalazł. Wypięte pośladki aż "proszą się" o działanie.</span></p><p><span>Chciałaś połączyć seks z intensywnym treningiem nóg? Udało się!</span></p><p><span><span>Partnerka musi mieć naprawdę silne nogi, jeśli ma mieć szansę utrzymać ciężar ciała.</span></span></p><p><span><span>Jeśli nie macie zbyt stabilnego mebla lub kondycji, pozycję lepiej zmodyfikować. Proponowany wcześniej <b>siad w rękach</b> jest łatwiejszy, a zarazem gwarantuje intensywniejsze doznania, bo wasze ciała są bliżej. </span></span></p>', '', 'ZG'),
        (129, 'Pozycja seksualna: Y', '', '<p><b>Uścisk ogiera</b> też można skomplikować. Oto dowód.</p><p><b><span>Jak to wygląda?<br></span></b></p><p><span>Kobieta kładzie się na brzuchu i delikatnie zsuwa z łóżka tak, by ręce znalazły się na podłodze. Partner łagodnie rozsuwa nogi partnerki, kładzie się między nimi i wprowadza członka do waginy. Dłonie zostawia na pośladkach i podnosi tułów do góry.</span></p><p><span><b>Zalety:</b></span></p><p><span>To na pewno ciekawa odmiana, a zarazem ta <b>pozycja</b> wbrew pozorom nie wymaga cyrkowych umiejętności.</span></p><p><span>Niektóre kobiety w tej pozycji odczuwają wyjątkowo silną stymulację, którą mogą regulować nieznacznie balansując ciałem.</span></p><p><b><span>Warto wiedzieć:<br></span></b></p><p><span>Jeśli on nie ma mocnych pleców, nie będzie łatwo. Kochance może zakręcić się w głowie. Wasze ciała stykają się tylko od pasa w dół, a to nie wszystkie panie lubią.<br></span></p>', '', 'ZG'),
        (130, 'Pozycja seksualna: tron cesarza', '', '<p>Tron cesarza ma wszystkie wady <b>pozycji na napastnika</b>, a dodatkowo jest jeszcze niewygodny dla mężczyzny. Jeśli jednak się upieracie i się wam uda, finał będzie przyjemny dla obojga.<b> </b></p><p><span><b>Jak to wygląda?</b><br></span></p><p><span>Mężczyzna siada z wyprostowanymi nogami (może też usiąść na łydkach), a kobieta dosiada go tyłem. Zgina nogi w kolanach i nogi również do tyłu. <br></span></p><p><span><b>Zalety:</b></span></p><p><span>Główna zaletą jest wolne tempo stosunku.</span></p><p><span>Kobieta może nie tylko wykonywać ruchy góra-dół, przód-tył, ale także rozchylać nogi i w ten sposób dostarczać dodatkowe bodźce.</span></p><p><span>Mężczyzna może swobodnie pieścić <b>piersi</b> kobiety (ręce ma wolne), a zarazem cieszyć się dłużej seksem.</span></p><p><span><span>Pozycja wykorzystywana wspomagająco w leczeniu przedwczesnego wytrysku (chociaż są lepsze). Stosunek potrwa rzeczywiście dłużej, jeśli będzie odbywał się w wolnym</span><span> tempie, a na nie ma wpływ przede wszystkim kobieta, co ogranicza kontrolę partnera.</span></span></p>', '', 'ZG'),
        (131, 'Pozycja seksualna: pułapka', '', '<p><span>To dość skomplikowane, chociaż wydaje się bardzo podobne do wcześniejszych, łatwiejszych pozycji.</span></p><p><span>On klęczy na jednym kolanie, odchyla się delikatnie w bok i dodatkowo podpiera ręką. Drugą nogę w kolanie zgina, stawia na podłodze i "kładzie" na podłożu. Kobieta opiera się na przedramionach i bardzo mocno zadziera pośladki. </span></p><p><b><span>Zalety<br></span></b></p><p><span>Kobieta marzy o pełnej dominacji mężczyzny? On rzeczywiście łapie ją w <b>pułapkę</b>.<br></span></p><p><span>Pozycja zapewnia głęboką penetrację. <span>Wolną ręką mężczyzna może pieścić pośladki bądź piersi partnerki.</span></span></p><p><b><span>Warto wiedzieć:<br></span></b></p><p><span>Zmęczenie przyjdzie pewnie dość szybko. Biodra, kolana, nawet st</span><span>opy: w tej pozycji nogi nie mają lekko.</span><b><span> </span></b></p><p><span>Zaboleć mogą też ręce (jej łokcie, jego dłonie), a nawet odcinek szyjny kręgosłupa.</span></p>', '', 'ZG'),
        (132, 'Pozycja seksualna: odwrócone H', '', '<p>Pozycje coraz trudniejsze, a satysfakcja niejednokrotnie marna. Wasza decyzja...</p><p><span><b>Jak to wygląda?<br></b></span></p><p><span> </span><span>Kobieta stoi i pochyla się tak, by położyć dłonie na podłodze. Wypina pośladki (może stanąć w lekkim rozkroku). Nie trzeba wielkiej wyobraźni, by dostrzec, że w tej pozycji absolutną i pełną kontrolę ma mężczyzna.</span></p><p><span>Wystarczy, że dotrwacie do orgazmu. Na pewno będą powody do dumy.<br></span></p><p><span> </span><span><b>Warto wiedzieć:</b></span></p><p><span> </span><span>Jeśli partnerka nie jest aż tak wygimnastykowana, by dotknąć dłońmi podłogi, może delikatnie ugiąć nogi w kolanach lub podeprzeć się o krzesło lub łóżko.</span></p><p><span>Kobiety tej pozycji zazwyczaj nie lubią, bo wysiłek nie jest wart efektu.<br></span></p>', '', 'ZG'),
        (133, 'Pozycja seksualna: trzcina na wietrze', '', '<p><span>Jeszcze macie mało? Tak, <b>odwrócone H</b> można dodatkowo utrudnić.<br></span></p><p><span><b>Jak to wygląda?</b><br></span></p><p><span> </span><span>Kochanka mocno pochyla się do przodu i chwyta dłońmi za kostki. Pole manewru oczywiste, wyeksponowane i te widoki...</span></p><p><span>Satysfakcja (jeśli wam ta pozycja w ogóle wyjdzie) naprawdę duża dla obojga. Możliwa głęboka penetracja, a przy umiejętnym manewrowaniu pośladkami i udami spora szansa na skuteczną stymulację wrażliwych <b>stref erogennych</b>.</span></p><p><span>On ma wolne ręce, więc może w trakcie pieścić <b>łechtaczkę</b>.</span></p><p><b>Warto wiedzieć:</b></p><p><span>Nawet jeśli kobieta nie ma problemu z wykonaniem tak intensywnego skłonu, długo pozostać w tej pozycji się nie da, bo bolą plecy. Zresztą: nawet klasyczne pozycje stojące należą do męczących.</span></p>', '', 'ZG'),
        (134, 'Pozycja seksualna: krzesło pełne przyjemności', '', '<p>Kolejny wariant z wykorzystaniem mebla. Poziom trudności rośnie.</p><p><span>Chociaż to ciało kochanki przyjmie w tej pozycji kształt krzesła, stabilny mebel (łóżko, krzesło, taboret) też będzie potrzebny.</span></p><p><span>Kobieta staje na meblu. Mężczyzna ustawia się za nią tak, by jego tors zetknął się z plecami kochanki. Wówczas kobieta zgina kolana i przenosi <span>ciężar ciała </span>na tors mężczyzny. Mężczyzna wprowadza członka od tyłu, w zależności od pragnień obojga - do waginy lub odbytu.</span></p><p><b><span>Zalety:</span></b></p><p><span>Kobiety, które lubią pozycje od tyłu, doceniają w tej pozycji bliski kontakt z partnerem. Nie można wprawdzie patrzeć sobie w oczy, ale dotykacie się intensywnie. On daje oparcie, a jego wolne ręce mogą błądzić po ciele i je pieścić.</span></p><p><span>Wiele par w tej pozycji przeżywa intensywny <b>orgazm</b>.</span></p><p><b><span>Warto wiedzieć:<br></span></b></p><p><span>Jeśli kochanka ma słabe nogi, to długo nie potrwa. To dla kobiety ta pozycja jest szczególnie obciążająca.</span></p><p><span>Jeśli on nie jest wystarczająco silny, trudno mu będzie podtrzymywać słodki ciężar wybranki i możecie oboje się przewrócić.</span></p><p><span>Zbliżone, silne doznania seksualne są także w wersjach łatwiejszych.</span></p>', '', 'ZG'),
        (135, 'Pozycja seksualna: hydrant', '', '<p>Ta kobieta nie ma trzech nóg. Jej kochanek też klęczy i jest bardzo blisko.</p><p><span><b>Jak to wygląda?</b></span></p><p><span> </span><span>Kobieta klęczy podparta na dłoniach i podnosi jedną nogę. Za nią na jednym kolanie klęczy mężczyzna, a podniesioną nogę kobiety kładzie na swojej. Drugą nogę ma zgiętą w kolanie i ustawioną pod kątem. Aby zachować równowagę i mieć większą kontrolę nad ruchami, trzyma dłonie na biodrach partnerki.</span></p><p><span>Bardzo umowne. Wiele par (zwłaszcza kobiet) nie lubi tej pozycji, nawet jej nie rozumie. <br></span></p><p><span> </span><span><b>Warto wiedzieć:</b></span></p><p><span> </span><span>Głębokie pchnięcia i specyficzne ustawienie umożliwia stymulację <b>punktu G</b>. Niestety, pozycja może okazać się wyczerpująca. Aby tego uniknąć, warto zamieniać nogi. Kobieta może również klęknąć przy jakimś oparciu, aby łatwiej jej było utrzymać równowagę.</span></p>', '', 'ZG'),
        (136, 'Pozycja seksualna: nożyce', '', '<p>Czas na właściwie nożyce, Niełatwe, ale warto.</p><p><span>On siada i prostuje nogi, a następnie unosi się na wyprostowanych rękach i unosi pośladki. Ona kładzie się na nim tyłem do jego twarzy. Kobieta prostuje nogi, a opiera się na wyprostowanych rękach.<br></span></p><p><span>Pozycja ciekawa, wyjątkowa, zaskakująca nawet dla wytrawnych kochanków. Zapewnia silne doznania wzrokowe mężczyźnie.</span></p><p><span><b>Nożyce</b> lubią kobiety, które chętnie przejmują inicjatywę w seksie.</span></p><p><span>Zaboleć może każda kończyna: jej i jego. Nietrudno też nadwyrężyć <b>kręgosłup</b>.<br></span></p><p><span>Ciała kochanków przyjmują w tej <b>pozycji</b> kształt rozwartych nożyc. To te <b>nożyce</b> są najbardziej znane, ale Kamasutra zna jednak jeszcze inne. Poza prezentowanymi wyżej, warto zobaczyć jeszcze</span><b><span> nożyce, wariant pozycji klasycznej.</span></b></p>', '', 'ZG'),
        (137, 'Pozycja seksualna: taczka', '', '<p>Na koniec klasyczne taczki. Warto?</p><p><span><b>Jak to wygląda?</b></span></p><p><span> </span><span>Kobieta kładzie się na brzuchu. Partner chwyta ją za uda i podnosi do góry, partnerka zaś unosi tułów i opiera jego ciężar na wyprostowanych rękach. </span></p><p><span>Penetracja w tej pozycji może być bardzo głęboka.</span></p><p><span>Jeśli lubicie opowiadać o waszym życiu intymnym, gdy wyjdzie, można się pochwalić. Jak nie, zresztą również.<br></span></p><p><span> </span><span><b>Warto wiedzieć:</b></span></p><p><span> </span><span>Mimo że pozycja nie wymaga specjalnej techniki, obie strony muszą mieć dość siły, by utrzymać równowagę. Jeśli jest to dla kobiety zbyt niewygodne, może podeprzeć tułów na przedramionach - wtedy ciężar ciała przesuwa się na klatkę piersiową, a nie na dłonie, co jest mniej męczące i umożliwia dłuższą, intensywniejszą i mniej wyczerpującą penetrację.</span></p>', '', 'ZG');